        .preview-card {
            background: var(--canva-bg);
            border-radius: 12px;
            padding: 24px;
            box-shadow: var(--canva-shadow-sm);
        }

        .preview-img {
            width: 100%;
            max-height: 400px;
            object-fit: contain;
            border-radius: var(--canva-radius);
        }

        .image-info {
            display: flex;
            gap: 16px;
            margin-top: 16px;
            font-size: 13px;
            color: var(--canva-text-light);
        }

        .info-badge {
            background: var(--canva-bg-light);
            padding: 6px 12px;
            border-radius: 6px;
        }

        /* Crop Canvas */
        .crop-section {
            width: 100%;
            max-width: 800px;
            margin-top: 24px;
            display: none;
        }

        .crop-card {
            background: var(--canva-bg);
            border-radius: 12px;
            padding: 24px;
            box-shadow: var(--canva-shadow-sm);
        }

        .crop-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            margin-bottom: 20px;
        }

        .crop-title {
            font-size: 16px;
            font-weight: 600;
            color: var(--canva-text);
        }

        .size-badge {
            background: linear-gradient(135deg, var(--canva-purple), var(--canva-blue));
            color: white;
            padding: 6px 12px;
            border-radius: 6px;
            font-size: 13px;
            font-weight: 600;
        }

        .crop-canvas-wrapper {
            background: #fafafa;
            border-radius: var(--canva-radius);
            padding: 20px;
