        }

        /* Sidebar Sections */
        .sidebar-section {
            margin-bottom: 24px;
        }

        .section-title {
            font-size: 13px;
            font-weight: 700;
            color: var(--canva-text);
            text-transform: uppercase;
            letter-spacing: 0.5px;
            margin-bottom: 12px;
        }

        /* Size Grid */
        .size-grid {
            display: grid;
            gap: 8px;
        }

        .size-item {
            background: var(--canva-bg-light);
            border: 2px solid transparent;
            border-radius: var(--canva-radius);
            padding: 12px;
            cursor: pointer;
            transition: all 0.2s;
