                <div class="download-structure">
                    <div class="structure-title">
                        <span>📦</span>
                        <span>Organized Output</span>
                    </div>
                    <div class="structure-tree">
<span class="tree-folder">📁 your-images.zip</span>
  ├─ <span class="tree-folder">📁 2-3_ratio/</span>
  │  ├─ <span class="tree-file">24x36.jpg</span>
  │  └─ <span class="tree-file">24x36.pdf</span>
  ├─ <span class="tree-folder">📁 3-4_ratio/</span>
  │  ├─ <span class="tree-file">18x24.jpg</span>
  │  └─ <span class="tree-file">18x24.pdf</span>
  ├─ <span class="tree-folder">📁 4-5_ratio/</span>
  │  ├─ <span class="tree-file">8x10.jpg</span>
  │  └─ <span class="tree-file">8x10.pdf</span>
  └─ <span class="tree-folder">📁 a_paper/</span>
     ├─ <span class="tree-file">a1.jpg</span>
     └─ <span class="tree-file">a1.pdf</span>
                    </div>
