        </div>

        <!-- Right Sidebar -->
        <div class="sidebar-right">
            <div class="sidebar-section">
                <div class="section-title">Adjust Framing</div>

                <div class="control-group">
                    <div class="control-label">
                        <span>↔️ Horizontal</span>
                        <span class="control-value" id="posXValue">50%</span>
                    </div>
                    <input type="range" min="0" max="100" value="50" class="slider" id="posXSlider">
                </div>

                <div class="control-group">
                    <div class="control-label">
                        <span>↕️ Vertical</span>
