                    <li class="feature-item">
                        <div class="feature-icon">🎯</div>
                        <div class="feature-content">
                            <div class="feature-title">Perfect Composition</div>
                            <div class="feature-desc">Adjust each size individually</div>
                        </div>
                    </li>
                    <li class="feature-item">
                        <div class="feature-icon">📐</div>
                        <div class="feature-content">
                            <div class="feature-title">300 DPI Output</div>
                            <div class="feature-desc">Print-ready quality</div>
                        </div>
                    </li>
                    <li class="feature-item">
                        <div class="feature-icon">🔒</div>
                        <div class="feature-content">
                            <div class="feature-title">100% Private</div>
