    <!-- Loading Overlay -->
    <div class="loading-overlay" id="loadingOverlay">
        <div class="loading-content">
            <div class="spinner"></div>
            <div class="loading-text">Processing your images...</div>
        </div>
    </div>

    <!-- Status Message -->
    <div class="status-message" id="statusMessage">
        <div class="status-icon" id="statusIcon"></div>
        <div class="status-text" id="statusText"></div>
    </div>

    <script>
        // Size configurations with folder organization
        const SIZES = [
            { id: '24x36', width: 24, height: 36, label: '24×36 in', type: '2:3 Ratio', folder: '2-3_ratio', filename: '24x36' },
            { id: '18x24', width: 18, height: 24, label: '18×24 in', type: '3:4 Ratio', folder: '3-4_ratio', filename: '18x24' },
            { id: '8x10', width: 8, height: 10, label: '8×10 in', type: '4:5 Ratio', folder: '4-5_ratio', filename: '8x10' },
            { id: '23.4x33.1', width: 23.4, height: 33.1, label: '23.4×33.1 in', type: 'A1 Paper', folder: 'a_paper', filename: 'a1' },
            { id: '16.5x23.4', width: 16.5, height: 23.4, label: '16.5×23.4 in', type: 'A2 Paper', folder: 'a_paper', filename: 'a2' },
            { id: '11.7x16.5', width: 11.7, height: 16.5, label: '11.7×16.5 in', type: 'A3 Paper', folder: 'a_paper', filename: 'a3' },
            { id: '8.3x11.7', width: 8.3, height: 11.7, label: '8.3×11.7 in', type: 'A4 Paper', folder: 'a_paper', filename: 'a4' },
            { id: '5.8x8.3', width: 5.8, height: 8.3, label: '5.8×8.3 in', type: 'A5 Paper', folder: 'a_paper', filename: 'a5' },
            { id: '5x7', width: 5, height: 7, label: '5×7 in', type: 'Standard', folder: 'standard', filename: '5x7' },
            { id: '11x14', width: 11, height: 14, label: '11×14 in', type: 'Standard', folder: 'standard', filename: '11x14' }
        ];

        // State
        let state = {
            originalImage: null,
            currentSizeId: '24x36',
            cropSettings: {},
            imageInfo: {}
        };

        // DOM Elements
        const elements = {
            fileInput: document.getElementById('fileInput'),
            uploadBtn: document.getElementById('uploadBtn'),
            uploadArea: document.getElementById('uploadArea'),
            previewSection: document.getElementById('previewSection'),
            cropSection: document.getElementById('cropSection'),
            originalPreview: document.getElementById('originalPreview'),
            imageInfo: document.getElementById('imageInfo'),
            processBtn: document.getElementById('processBtn'),
            resetBtn: document.getElementById('resetBtn'),
            loadingOverlay: document.getElementById('loadingOverlay'),
            statusMessage: document.getElementById('statusMessage'),
            statusIcon: document.getElementById('statusIcon'),
            statusText: document.getElementById('statusText'),
            filenameInput: document.getElementById('filenameInput'),
            sizeGrid: document.getElementById('sizeGrid'),
            cropCanvas: document.getElementById('cropCanvas'),
            currentSizeLabel: document.getElementById('currentSizeLabel'),
            posXSlider: document.getElementById('posXSlider'),
            posYSlider: document.getElementById('posYSlider'),
            zoomSlider: document.getElementById('zoomSlider'),
            rotateSlider: document.getElementById('rotateSlider'),
            posXValue: document.getElementById('posXValue'),
            posYValue: document.getElementById('posYValue'),
            zoomValue: document.getElementById('zoomValue'),
            rotateValue: document.getElementById('rotateValue')
        };

        // Initialize
        function init() {
            initializeCropSettings();
            renderSizeGrid();
            setupEventListeners();
        }

        // Initialize crop settings for all sizes
        function initializeCropSettings() {
            SIZES.forEach(size => {
                state.cropSettings[size.id] = {
                    posX: 50,
                    posY: 50,
                    zoom: 80,
                    rotation: 0
                };
            });
        }

        // Render size grid
        function renderSizeGrid() {
            elements.sizeGrid.innerHTML = SIZES.map((size, index) => `
                <div class="size-item ${index === 0 ? 'selected' : ''}" 
                     data-size-id="${size.id}"
                     onclick="selectSize('${size.id}')">
                    <div class="size-info">
                        <div class="size-name">${size.label}</div>
                        <div class="size-type">${size.type}</div>
                    </div>
                    <div class="size-check">${index === 0 ? '✓' : ''}</div>
                </div>
            `).join('');
        }

        // Setup event listeners
        function setupEventListeners() {
            elements.uploadBtn.addEventListener('click', () => elements.fileInput.click());

            elements.fileInput.addEventListener('change', (e) => {
                if (e.target.files && e.target.files[0]) {
                    handleImageUpload(e.target.files[0]);
                }
            });

            elements.uploadArea.addEventListener('dragover', (e) => {
                e.preventDefault();
                elements.uploadArea.classList.add('active');
            });

            elements.uploadArea.addEventListener('dragleave', () => {
                elements.uploadArea.classList.remove('active');
            });

            elements.uploadArea.addEventListener('drop', (e) => {
                e.preventDefault();
                elements.uploadArea.classList.remove('active');
                if (e.dataTransfer.files && e.dataTransfer.files[0]) {
                    handleImageUpload(e.dataTransfer.files[0]);
                }
            });

            elements.uploadArea.addEventListener('click', () => elements.fileInput.click());

            elements.posXSlider.addEventListener('input', () => updateCropSetting('posX'));
            elements.posYSlider.addEventListener('input', () => updateCropSetting('posY'));
            elements.zoomSlider.addEventListener('input', () => updateCropSetting('zoom'));
            elements.rotateSlider.addEventListener('input', () => updateCropSetting('rotation'));

            elements.processBtn.addEventListener('click', processImages);
            elements.resetBtn.addEventListener('click', resetAllCrops);
        }

        // Handle image upload
        function handleImageUpload(file) {
            if (!file.type.match('image.*')) {
                showStatus('Please upload an image file.', 'error');
                return;
            }

            const reader = new FileReader();
            reader.onload = (e) => {
                const img = new Image();
                img.onload = () => {
                    state.originalImage = img;
                    state.imageInfo = {
                        width: img.width,
                        height: img.height,
                        size: (file.size / 1024 / 1024).toFixed(2)
                    };

                    elements.originalPreview.src = e.target.result;
                    elements.imageInfo.innerHTML = `
                        <span class="info-badge">${img.width} × ${img.height} px</span>
                        <span class="info-badge">${state.imageInfo.size} MB</span>
                    `;

                    elements.previewSection.style.display = 'block';
                    elements.cropSection.style.display = 'block';

                    const originalName = file.name.split('.')[0];
                    elements.filenameInput.value = originalName + '-cropped';

                    updateCropPreview();
                    elements.processBtn.disabled = false;
                };
                img.src = e.target.result;
            };
            reader.readAsDataURL(file);
        }

        // Select size
        function selectSize(sizeId) {
            state.currentSizeId = sizeId;

            document.querySelectorAll('.size-item').forEach(item => {
                const isSelected = item.dataset.sizeId === sizeId;
                item.classList.toggle('selected', isSelected);
                const checkmark = item.querySelector('.size-check');
                checkmark.textContent = isSelected ? '✓' : '';
            });

            const size = SIZES.find(s => s.id === sizeId);
            elements.currentSizeLabel.textContent = size.label;

            const settings = state.cropSettings[sizeId];
            elements.posXSlider.value = settings.posX;
            elements.posYSlider.value = settings.posY;
            elements.zoomSlider.value = settings.zoom;
            elements.rotateSlider.value = settings.rotation;

            updateSliderValues();
            updateCropPreview();
        }

        // Update crop setting
        function updateCropSetting(property) {
            const sliderMap = {
                posX: elements.posXSlider,
                posY: elements.posYSlider,
                zoom: elements.zoomSlider,
                rotation: elements.rotateSlider
            };

            state.cropSettings[state.currentSizeId][property] = parseInt(sliderMap[property].value);
            updateSliderValues();
            updateCropPreview();
        }

        // Update slider value displays
        function updateSliderValues() {
            const settings = state.cropSettings[state.currentSizeId];
            elements.posXValue.textContent = settings.posX + '%';
            elements.posYValue.textContent = settings.posY + '%';
            elements.zoomValue.textContent = settings.zoom + '%';
            elements.rotateValue.textContent = settings.rotation + '°';
        }

        // Calculate crop region from original image
        function calculateCropRegion(imgWidth, imgHeight, targetWidth, targetHeight, settings) {
            const targetAspect = targetWidth / targetHeight;
            const imgAspect = imgWidth / imgHeight;

            let cropWidth, cropHeight;

            if (imgAspect > targetAspect) {
                cropHeight = imgHeight;
                cropWidth = imgHeight * targetAspect;
            } else {
                cropWidth = imgWidth;
                cropHeight = imgWidth / targetAspect;
            }

            const zoomFactor = settings.zoom / 100;
            cropWidth = cropWidth * zoomFactor;
            cropHeight = cropHeight * zoomFactor;

            cropWidth = Math.min(cropWidth, imgWidth);
            cropHeight = Math.min(cropHeight, imgHeight);

            const maxOffsetX = imgWidth - cropWidth;
